import React, { useEffect, useRef, useState } from "react";

const SETTINGS = {
  SENSITIVITY: 1.8,
  STEP_LEAD: 1.10,
  FREEZE_THRESHOLD: 2500, // 2.5 seconds
  // Maps your UI strings to starting BPMs
  CADENCE_MAP: { slow: 70, medium: 90, fast: 110 }
};

export default function EeshaWalkComponent({ cadence, onStop }) {
  const [detectedBpm, setDetectedBpm] = useState(0);
  const [isFrozen, setIsFrozen] = useState(false);
  
  // We use a Ref for the engine state so the high-frequency 
  // sensor data doesn't trigger 60+ React re-renders per second.
  const engine = useRef({
    isRunning: true,
    audioCtx: null,
    lastStepTime: Date.now(),
    currentBpm: SETTINGS.CADENCE_MAP[cadence] || 90,
    fastWin: [],
    slowWin: [],
    side: 0, // 0 for Left, 1 for Right
  });

  useEffect(() => {
    startSensors();
    return () => stopSensors();
  }, []);

  const startSensors = async () => {
    // 1. Request iOS Permissions
    if (typeof DeviceMotionEvent.requestPermission === 'function') {
      try {
        const permission = await DeviceMotionEvent.requestPermission();
        if (permission !== 'granted') {
          alert("Permission denied. Synova needs motion access to track steps.");
          return onStop();
        }
      } catch (e) {
        console.error(e);
        return onStop();
      }
    }

    // 2. Setup Audio
    engine.current.audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    
    // 3. Listen for Movement
    window.addEventListener('devicemotion', handleMotion);
    
    // 4. Start Metronome Loop
    runMetronome();
  };

  const stopSensors = () => {
    engine.current.isRunning = false;
    window.removeEventListener('devicemotion', handleMotion);
    if (engine.current.audioCtx) engine.current.audioCtx.close();
  };

  const handleMotion = (event) => {
    const acc = event.acceleration;
    if (!acc || !acc.z) return;

    // Calculate magnitude (Z-focus like your Python script)
    const mag = Math.abs(acc.z);
    const { fastWin, slowWin } = engine.current;

    fastWin.push(mag);
    if (fastWin.length > 5) fastWin.shift();
    slowWin.push(mag);
    if (slowWin.length > 30) slowWin.shift();

    if (slowWin.length < 30) return;

    // Dual Moving-Average Logic
    const fastAvg = fastWin.reduce((a, b) => a + b) / fastWin.length;
    const slowAvg = slowWin.reduce((a, b) => a + b) / slowWin.length;
    const ratio = fastAvg / (slowAvg + 0.0001);

    const now = Date.now();
    // Step detected!
    if (ratio > SETTINGS.SENSITIVITY && (now - engine.current.lastStepTime) > 300) {
      const interval = now - engine.current.lastStepTime;
      const stepBpm = 60000 / interval;
      
      // Update engine cadence (1.10 lead)
      engine.current.currentBpm = stepBpm * SETTINGS.STEP_LEAD;
      engine.current.lastStepTime = now;
      
      // Update UI
      setDetectedBpm(Math.round(stepBpm));
      setIsFrozen(false);
    }
  };

  const runMetronome = () => {
    if (!engine.current.isRunning) return;

    const now = Date.now();
    const timeSinceLast = now - engine.current.lastStepTime;
    let nextDelay;

    // Freeze Detection logic
    if (timeSinceLast > SETTINGS.FREEZE_THRESHOLD) {
      setIsFrozen(true);
      playClick(1500, 0); // High pitch rescue beat, center pan
      nextDelay = 450;    // Faster "emergency" rhythm
    } else {
      // Alternating Stereo Pan
      const pan = engine.current.side === 0 ? -0.7 : 0.7;
      playClick(800, pan);
      engine.current.side = 1 - engine.current.side;
      
      // Calculate interval based on current lead BPM
      nextDelay = 60000 / Math.max(40, Math.min(160, engine.current.currentBpm));
    }

    setTimeout(runMetronome, nextDelay);
  };

  const playClick = (freq, panValue) => {
    const ctx = engine.current.audioCtx;
    if (!ctx) return;
    
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const panner = ctx.createStereoPanner();
    const gain = ctx.createGain();

    osc.frequency.setValueAtTime(freq, now);
    panner.pan.setValueAtTime(panValue, now);
    
    gain.gain.setValueAtTime(0.4, now);
    gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);

    osc.connect(panner).connect(gain).connect(ctx.destination);
    
    osc.start(now);
    osc.stop(now + 0.1);
  };

  return (
    <div className={`walk-setup ${isFrozen ? "freeze-active" : ""}`}>
      <div className="walk-cue">
        {isFrozen ? "Keep moving to break the freeze" : "Walking in Sync"}
      </div>

      <div style={{ textAlign: 'center', margin: '40px 0' }}>
        <h1 style={{ fontSize: '80px', color: 'var(--accent)', margin: 0 }}>
          {detectedBpm || "--"}
        </h1>
        <p className="cadence-label">Your BPM</p>
      </div>

      <button className="walk-start-btn" onClick={onStop} style={{ background: '#331a1a', color: '#ff4d4d' }}>
        Stop Session
      </button>
    </div>
  );
}
